import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

describe('Dirty error handling', () => {
  it('should not emit load event when a non-ENOENT error occurs', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const filePath = path.join(tmpDir, 'noperm.db');
    fs.writeFileSync(filePath, '');
    fs.chmodSync(filePath, 0o000);

    const { Dirty } = require('../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js');
    const db = new Dirty(filePath);

    let loadEmitted = false;

    db.on('load', () => { loadEmitted = true; });
    db.on('error', () => {
      setImmediate(() => {
        fs.chmodSync(filePath, 0o644);
        fs.rmSync(tmpDir, { recursive: true, force: true });
        expect(loadEmitted).toBe(false);
        done();
      });
    });
  });
});
