    let loadEmitted = false;

    db.on('load', () => {
      loadEmitted = true;
    });

    db.on('error', (err: NodeJS.ErrnoException) => {
      setImmediate(() => {
        try {
          fs.chmodSync(filePath, 0o644);
        } catch (_) {}
        try {
          fs.rmSync(tmpDir, { recursive: true, force: true });
